mapper.select:
SELECT COUNT(*)
FROM store_inventory
WHERE store_id = #{storeId}

mapper.update:
UPDATE store_inventory
SET safety_stock_qty = #{safetyStockQty},
    auto_order_qty   = #{autoOrderQty}
WHERE store_id = #{storeId}
  AND product_id = #{productId}

UPDATE store_inventory
SET current_stock_qty = #{newQty}
WHERE store_id = #{storeId}
  AND product_id = #{productId}

mapper.select:
SELECT l.*, p.name as productName
FROM inventory_logs l
JOIN products p ON l.product_id = p.product_id
WHERE l.store_id = #{storeId}

    AND l.product_id = #{productId}

ORDER BY l.created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM inventory_logs
WHERE store_id = #{storeId}

    AND product_id = #{productId}
